def get_all_merchants() -> list:
    return SAMPLE_MERCHANTS


def get_by_neighborhood(neighborhood: str) -> list:
    n = neighborhood.lower()
    return [m for m in SAMPLE_MERCHANTS if n in (m.get("neighborhood") or "").lower()]


def get_by_mcc_category(category: str) -> list:
    c = category.lower()
    return [m for m in SAMPLE_MERCHANTS
            if any(c in cat.lower() for cat in (m.get("categories") or "").split(","))]
